import{e as a,f as s,D as t}from"./framework.16919e8f.js";const i='{"title":"Шаттримшаттаттвасандоха","description":"","frontmatter":{"title":"Шаттримшаттаттвасандоха","subtitle":"Собрание тридцати шести таттв","sans":"षट्त्रिंशत्तत्त्वसन्दोह","trans":"Ṣaṭtriṁśattattvasandoha","tags":"text","date":"2021-05-05T00:00:00.000Z"},"relativePath":"texts/shattrimshattattva/index.md","lastUpdated":1625417265796}',r={},p=t('<p>Amṛtānandanātha, 12 век н.э. Перевод с санскрита Ерченкова О. Н.</p><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">यदयमनुत्तरमूर्तिर्नजेच्छयाखिलमिदं जगत्स्रष्टुम्।<br> पस्पन्दे स स्पन्दः प्रथमः शिवतत्त्वमुच्यते तज्ज्ञैः॥१॥</p><p class="trans">Yadayamanuttaramūrtirnijecchayākhilamidaṁ jagatsraṣṭum।<br> Paspande sa spandaṭ prathamaṭ śivatattvamucyate tajjñaiṭ॥1॥</p><p>Наивысший Образ (Абсолюта, Ануттара мурти), творящий Своей Волей всю эту вселенную - пульсирующая спанда, именуется знающими первой, Шива таттвой.</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">इच्छा सैव स्वच्छा सन्ततसमवायिनी सती शक्तिः।<br> सचराचरस्य जगतो बीजं निखिलस्य निजनिलीनस्य॥२॥</p><p class="trans">Icchā saiva svacchā santatasamavāyinī sati śaktiḥ।<br> Sacarācarasya jagato bījaṁ nikhilasya nijanilīnasya॥2॥</p><p>Сущая иччха Шакти – (Его) вечная неотъемлемая собственная Воля. (Она) – семя всей движущейся и неподвижной вселенной и Его собственной трансформации.</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">स्वेच्छाशक्त्युद्गीर्णं जगदात्मतया समाच्छाद्य।<br> निवसन् स एव निखिलानुग्रहनिरतः सदाशिवोऽभिहितः॥३॥</p><p class="trans">Svecchāśaktyudgīrṇaṁ jagadātmatayā samācchādya।<br> Nivasan sa eva nikhilānugrahanirataḥ sadāśivo&#39;bhihitaḥ॥3॥</p><p>Благодаря Своей иччха шакти, переполняющей сущность вселенной (джагатдатма), проявляется и существует Садашива, являющий всю милость.</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">विश्वं पश्चात्पश्यनिदन्तया निखिलमीश्वरो जातः।<br> सा भवति शुद्धविद्या येदन्ताहन्तयोरभेदमतिः॥४॥</p><p class="trans">Viśvaṁ pañcātpaśyanidantayā nikhilamīśvaro jātaḥ।<br> Sā bhavati śuddhavidyā yedantāhantayorabhedamatiḥ॥4॥</p><p>Затем появляется Ишвара, зрящий всю вселенную, посредством чувства «этого» (иданта). (Затем) является шуддха видья, в которой «Я» и «То» - нераздельны.</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">माया विभेदबुद्धिर्निजांशजातेषु निखिलजीवेषु।<br> नित्यं तस्य निरङ्कुशविभवं वेलेव वारिधे रुन्धे॥५॥</p><p class="trans">Māyā vibhedabuddhirnijāṁśajāteṣu nikhilajīveṣu।<br> Nityaṁ tasya niraṅkuśavibhavaṁ veleva vāridhe rundhe॥5॥</p><p>Его (Парамешвары) Разум (буддхи), который есть Майа (таттва) разделяется на части среди джив, являющихся порожденными им частями и ограничивает их, подобно берегу, ограничивающему океан. Но, даже будучи (погруженным) в нечистый порядок, Парамешвара вечно (остается обладателем) Своего независимого могущества.</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">स तया परिमितमूर्तिः सङ्कुचितसमस्तशक्तिरेष पुमान्।<br> रविरिव सन्ध्यारक्तः संहृतशक्तिः स्वभासनेऽप्यपटुः॥६॥</p><p class="trans">Sa tayā parimitamūrtiḥ saṅkucitasamastaśaktireṣa pumān।<br> Raviriva sandhyāraktaḥ saṁhṛtaśaktiḥ svabhāsane&#39;pyapaṭuḥ॥6॥</p><p>Под влиянием этой ограничивающей Шакти Он (становится) пурушей(отдельным живым существом), подобно красному не жгучему солнцу, чью энергию забирает заря.</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">सम्पूर्णकर्तृताद्या बह्व्यः सन्त्यस्य शक्तयस्तस्य।<br> सङ्कोचात्सङ्कुचिताः कलादिरूपेण रूढयन्त्येवम्॥७॥</p><p class="trans">Sampūrṇakartṛtādyā bahvyaḥ santyasya śaktayastasya।<br> Saṅkocātsaṅkucitāḥ kalādirūpeṇa rūḍhayantyevam॥7॥</p><p>Множество присущих ему Шакти полноты, деятельности и прочего, будучи собранными, ограничивают его в форме калА (таттвы) и т.д.</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">तत्सर्वकर्तृता सा सङ्कुचिता कतिपयार्थमात्रपरा।<br> किञ्चित्कर्तारममुं कलयन्ती कीर्त्यते कला नाम॥८॥</p><p class="trans">Tatsarvakartṛtā sā saṅkucitā katipayārthamātraparā।<br> Kiñcitkartāramamuṁ kalayantī kīrtyate kalā nāma॥8॥</p><p>Ограничивающая (Шакти), именуется калА (Таттвой). Она ограничивает Его всемогущество и побуждает выполнять конкретную деятельность.</p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">सर्वज्ञतास्य शक्तिः परिमिततनुरल्पवेद्यमात्रपरा।<br> ज्ञानमुत्पादयन्ती विद्येति निगद्यते बुधैराद्यैः॥९॥</p><p class="trans">Sarvajñatāsya śaktiḥ parimitatanuralpavedyamātraparā।<br> Jñānamutpādayantī vidyeti nigadyate budhairādyaiḥ॥9॥</p><p>Шакти, ограничивающая Его всезнание, знанием относящимся только к телу, и порождающая (соответствующее) знание, именуется мудрыми видья таттвой.</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">नित्यपरिपूर्णतृप्तिः शक्तिस्तस्यैव परिमिता तु सती।<br> भोगेषु रञ्जयन्ती सततममुं रागतत्त्वतां याता॥१०॥</p><p class="trans">Nityaparipūrṇatṛptiḥ śaktistasyaiva parimitā tu satī।<br> Bhogeṣu rañjayantī satatamamuṁ rāgatattvatāṁ yātā॥10॥</p><p>Шакти, ограничивающая Его вечное совершенное удовлетворение, но являющаяся (Его) целомудренной супругой, царствующей постоянно в объектах наслаждения есть рага таттва - Его супруга.</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">सा नित्यतास्य शक्तिर्निकृष्य निधनोदयप्रदानेन।<br> नियतपरिच्छेदकरी कॢप्ता स्यात्कालतत्त्वरूपेण॥११॥</p><p class="trans">Sā nityatāsya śaktirnikṛṣya nidhanodayapradānena।<br> Niyataparicchedakarī kḷptā syātkālatattvarūpeṇa॥11॥</p><p>Шакти, ограничивающая Его вечность, наделяя появлением смерти и в форме кАла таттвы, является совершающей (Его) окончательное дробление.</p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">यास्य स्वतन्त्रताख्या शक्तिः सङ्कोचशालिनी सैव।<br> कृत्याकृत्येष्ववशं नियतममुं नियमयन्त्यभून्नियतिः॥१२॥</p><p class="trans">Yāsya svatantratākhyā śaktiḥ saṅkocaśālinī saiva।<br> Kṛtyākṛtyeṣvavaśaṁ niyatamamuṁ niyamayantyabhūnniyatiḥ॥12॥</p><p>Его Шакти, именуемая Самодостаточность (сватантрата) под влиянием которой появляется ограниченность, она же ограничивая себя причиной и следствием, становится нияти таттвой.</p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">इच्छादित्रिसमष्टिः शक्तिः शान्तास्य सङ्कुचद्रूपा।<br> सङ्कलितेच्छाद्यात्मकसत्त्वादिकसाम्यरूपिणी तु सती॥१३॥</p><p class="trans">Icchāditrisamaṣṭiḥ śaktiḥ śāntāsya saṅkucadrūpā।<br> Saṅkalitecchādyātmakasattvādikasāmyarūpiṇī tu satī॥13॥</p><p>Совокупность трех шакти, начиная с иччхи есть форма Покоя. Он есть сущее равновесие состоящее из Воли и прочего, саттвы и других (качеств).</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">बुद्ध्यादिसामरस्यस्वरूपचित्तात्मिका मता प्रकृतिः।<br> इच्छास्य रजोरूपाहङ्कृतिरासीदहम्प्रतीतिकरी॥१४॥</p><p class="trans">Buddhyādisāmarasyasvarūpacittātmikā matā prakṛtiḥ।<br> Icchāsya rajorūpāhaṅkṛtirāsīdahampratītikarī॥14॥</p><p>Совокупность буддхи и прочего, чья изначальная форма считается состоящей из Сознания - есть пракрити. Из иччхи, в образе раджаса, происходит эго, осуществляющее чувство «я».</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">ज्ञानापि सत्त्वरूपा निर्णयबोधस्य कारणं बुद्धिः।<br> तस्य क्रिया तमोमयमूर्तिर्मन उच्यते विकल्पकरी॥१५॥</p><p class="trans">Jñānāpi sattvarūpā nirṇayabodhasya kāraṇaṁ buddhiḥ।<br> Tasya kriyā tamomayamūrtirmana ucyate vikalpakarī॥15॥</p><p>Знание в форме саттвы, причина проявления Сознания, - есть разум (буддхи). Его деятельность в тамасе именуется умом (манасом), творящим мыслепредставления (викальпы).</p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">वामादिपञ्चभेदः स एव सङ्कुचितविग्रहो देवः।<br> ज्ञानक्रियोपरागप्राधान्याद्विविधविषयरूपोऽभूत्॥१६॥</p><p class="trans">Vāmādipañcabhedaḥ sa eva saṅkucitavigraho devaḥ।<br> Jñānakriyoparāgaprādhānyādvividhaviṣayarūpo&#39;bhūt॥16॥</p><p>Деление на Ваму и прочих, есть умаленный образ Бога. Он становится знанием, действием, окрашиванием, предшествующим форме разнообразных объектов.</p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">श्रोत्रं चक्षुः स्पर्शनजिह्वाघ्राणानि बोधकरणानि।<br> शब्दस्पर्शौ रूपं रसगन्धौ चेति भूतसूक्ष्माणि॥१७॥</p><p class="trans">Śrotraṁ cakṣuḥ sparśanajihvāghrāṇāni bodhakaraṇāni।<br> Śabdasparśau rūpaṁ rasagandhau ceti bhūtasūkṣmāṇi॥17॥</p><p>Ухо, глаз, кожа, язык, нос – инструменты сознания. Звук, прикосновение, форма, вкус, запах, - тонкие элементы.</p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">अयमेवातिनिकृष्टो जातो भूतात्मनापि भूतेशः।<br> गगनमनिलश्च तेजः सलिलं भूमिश्च पञ्चभूतानि॥१८॥</p><p class="trans">Ayamevātinikṛṣṭo jāto bhūtātmanāpi bhūteśaḥ।<br> Gaganamanilaśca tejaḥ salilaṁ bhūmiśca pañcabhūtāni॥18॥</p><p>Порождающий их, но незатронутый ими воплощенный Атман (Бхутатман) – есть владыка элементов Бхутеша. Пространство, воздух, огонь, вода и земля – пять (грубых) элементов.</p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">श्रोत्रादिकरणवेद्याः शब्दाद्यास्तानि वेदकान्येषाम्।<br> वचनकरी वागासीत् पाणिः स्यात्करणभूत आदाने॥१९॥</p><p class="trans">Śrotrādikaraṇavedyāḥ śabdādyāstāni vedakānyeṣām।<br> Vacanakarī vāgāsīt pāṇiḥ syātkaraṇabhūta ādāne॥19॥</p><p>Уши и прочие – постигающие органы, ими постигаются звук и другие (объекты). Язык есть (орган), творящий речь. Рука является органом хватания.</p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">गमनविसर्गानन्दत्रितये पादादिकं करणम्।<br> गन्धवती भूमिः स्यादापः सांसिद्धिकद्रवास्तेजः॥२०॥</p><p class="trans">Gamanavisargānandatritaye pādādikaṁ karaṇam।<br> Gandhavatī bhūmiḥ syādāpaḥ sāṁsiddhikadravāstejaḥ॥20॥</p><p>Ходьба, испражнение и наслаждение – (функция) трех (действующих) органов начиная с ног. Земля наделена запахом, вода наделена текучестью.</p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">उष्णस्पर्शमरूपस्पर्शो वायुरम्बरं सशब्दम्।<br> षट्त्रिंशत्तत्त्वमयं वन्दे कौलं कुलातिगं शम्भुम्॥२१॥</p><p class="trans">Uṣṇasparśamarūpasparśo vāyurambaraṁ saśabdam।<br> Ṣaṭtriṁśattattvamayaṁ vande kaulaṁ kulātigaṁ śambhum॥21॥</p><p>Огонь наделен теплом, прикосновением и формой, воздух (наделен) прикосновением, запахом и звуком. Я склоняюсь перед Шамбху, Каулой, превосходящим Кулу, состоящим из тридцати шести таттв.</p><p>Такова «Шатттримша таттва сандоха», сочиненная Амритананданатхой.</p></div><ul><li><p><a href="/books/SHattrimshattattva-sandoha.pdf" target="_blank">Перевод, исследование и комментарии к Шаттримшаттаттва-сандохе В.П. Иванова в составе «Розенберговского сборника»</a></p></li><li><p><a href="https://www.sanskrit-trikashaivism.com/ru/shattrimshattattvasandoha-1-trika-scriptures-non-dual-shaivism-of-kashmir-ru/544" class="external-link" target="_blank" rel="noopener noreferrer">Развернутый пословный перевод Ṣaṭtriṁśattattvasandoha на английский с комментарием Rājānakānanda (17 в.)</a></p></li></ul>',23);r.render=function(t,i,r,n,d,c){return a(),s("div",null,[p])};export default r;export{i as __pageData};
